import { useState, useEffect, useCallback } from 'react';
import {
    Box, Typography, Chip, Stack, Divider,
    IconButton, Tooltip, Select, MenuItem, FormControl, InputLabel,
} from '@mui/material';
import RestoreIcon from '@mui/icons-material/Restore';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import ExpandLessIcon from '@mui/icons-material/ExpandLess';
import DeleteSweepIcon from '@mui/icons-material/DeleteSweep';
import { DeletedServices, DeletedServicesError } from '@/api/deleted.api';
import { DeletedItem, CallStatus } from '@/types/api.types';
import { PageCard } from '@/components/PageCard';
import { PageContainer } from '@/components/PageContainer';
import { StatusMessage } from '@/components/StatusMessage';
import { ConfirmDialog } from '@/components/ui/ConfirmDialog';
import { safeJsonParse } from '@/utils/storage';
import { getApiError } from '@/utils/apiError';

const ENTITY_TYPE_OPTIONS = ['', 'Profile', 'Business', 'Event', 'Attendee'];

/** Maps each entity type to the JSON field name (PascalCase) used as the display label. */
const ENTITY_DISPLAY_FIELD: Record<string, string> = {
    Profile: 'Name',
    Business: 'Name',
    Event: 'Title',
    Attendee: 'Email',
};

function getDisplayLabel(item: DeletedItem): string {
    const field = ENTITY_DISPLAY_FIELD[item.entityType];
    if (!field) return item.entityId;
    const parsed = safeJsonParse<Record<string, unknown> | null>(item.data, null);
    const value = parsed?.[field];
    return typeof value === 'string' && value ? value : item.entityId;
}

export function AdminDeletedList() {
    const [items, setItems] = useState<DeletedItem[]>([]);
    const [status, setStatus] = useState<CallStatus>(CallStatus.InProgress);
    const [errorMsg, setErrorMsg] = useState('');
    const [correlationId, setCorrelationId] = useState<string | undefined>();
    const [entityTypeFilter, setEntityTypeFilter] = useState('');
    const [expandedId, setExpandedId] = useState<string | null>(null);
    const [restoreTarget, setRestoreTarget] = useState<DeletedItem | null>(null);
    const [isRestoring, setIsRestoring] = useState(false);
    const [restoreStatus, setRestoreStatus] = useState<CallStatus>(CallStatus.NotStarted);
    const [restoreError, setRestoreError] = useState('');

    const load = useCallback(async (filterType: string) => {
        setStatus(CallStatus.InProgress);
        setErrorMsg('');
        try {
            const res = await DeletedServices.GetDeleted(filterType || undefined);
            if (res.data?.status === 200) {
                setItems(res.data.result ?? []);
                setStatus(CallStatus.Success);
            } else {
                setErrorMsg(DeletedServicesError.GetDeletedError(res.data?.status ?? 0));
                setStatus(CallStatus.Failure);
            }
        } catch (err) {
            const info = getApiError(err);
            setErrorMsg(DeletedServicesError.GetDeletedError(info.httpStatus));
            setCorrelationId(info.correlationId);
            setStatus(CallStatus.Failure);
        }
    }, []);

    useEffect(() => { load(entityTypeFilter); }, [entityTypeFilter, load]);

    const handleRestore = async () => {
        if (!restoreTarget) return;
        setIsRestoring(true);
        setRestoreStatus(CallStatus.InProgress);
        setRestoreError('');
        try {
            const res = await DeletedServices.RestoreDeleted(restoreTarget.entityType, restoreTarget.entityId);
            if (res.data?.status === 200) {
                setRestoreStatus(CallStatus.Success);
                setItems(prev => prev.filter(
                    i => !(i.entityType === restoreTarget.entityType && i.entityId === restoreTarget.entityId)
                ));
                setRestoreTarget(null);
            } else {
                setRestoreError(DeletedServicesError.RestoreError(res.data?.status ?? 0));
                setRestoreStatus(CallStatus.Failure);
            }
        } catch (err) {
            setRestoreError(DeletedServicesError.RestoreError(getApiError(err).httpStatus));
            setRestoreStatus(CallStatus.Failure);
        } finally {
            setIsRestoring(false);
        }
    };

    const formatDate = (ms?: number) =>
        ms ? new Date(ms).toLocaleString() : '—';

    return (
        <PageContainer
            icon={<DeleteSweepIcon color="primary" />}
            title="Deleted Entities"
            subtitle="Browse and restore recently deleted records."
            action={
                <FormControl size="small" sx={{ minWidth: 160 }}>
                    <InputLabel>Entity Type</InputLabel>
                    <Select
                        value={entityTypeFilter}
                        label="Entity Type"
                        onChange={e => setEntityTypeFilter(e.target.value)}
                    >
                        {ENTITY_TYPE_OPTIONS.map(opt => (
                            <MenuItem key={opt} value={opt}>{opt || 'All'}</MenuItem>
                        ))}
                    </Select>
                </FormControl>
            }
        >
            <StatusMessage
                currentStatus={status}
                failureMessage={errorMsg}
                correlationId={correlationId}
            />

            {status === CallStatus.Success && items.length === 0 && (
                <PageCard>
                    <Typography color="text.secondary" align="center">No deleted items found.</Typography>
                </PageCard>
            )}

            {status === CallStatus.Success && items.map(item => {
                const id = `${item.entityType}::${item.entityId}`;
                const isExpanded = expandedId === id;
                return (
                    <PageCard key={id}>
                        <Stack direction="row" sx={{ alignItems: 'center' }} spacing={1}>
                            <Chip
                                label={item.entityType}
                                size="small"
                                color="error"
                                variant="outlined"
                                sx={{ borderRadius: 1, fontWeight: 600 }}
                            />
                            <Typography variant="body2" noWrap sx={{ color: 'text.secondary', flexGrow: 1, minWidth: 0 }}>
                                {getDisplayLabel(item)}
                            </Typography>
                            <Tooltip title="Restore">
                                <IconButton size="small" color="success" aria-label="Restore item" onClick={() => setRestoreTarget(item)}>
                                    <RestoreIcon fontSize="small" />
                                </IconButton>
                            </Tooltip>
                            <Tooltip title={isExpanded ? 'Collapse' : 'View data'}>
                                <IconButton size="small" aria-label={isExpanded ? 'Collapse details' : 'Expand details'} onClick={() => setExpandedId(isExpanded ? null : id)}>
                                    {isExpanded ? <ExpandLessIcon fontSize="small" /> : <ExpandMoreIcon fontSize="small" />}
                                </IconButton>
                            </Tooltip>
                        </Stack>
                        <Typography variant="caption" sx={{ color: 'text.disabled', mt: 0.5, display: 'block' }}>
                            {formatDate(item.deletedAt)}
                        </Typography>

                        {isExpanded && (
                            <>
                                <Divider sx={{ my: 1 }} />
                                <Box
                                    component="pre"
                                    sx={{
                                        fontSize: '0.72rem',
                                        overflowX: 'auto',
                                        backgroundColor: 'action.hover',
                                        borderRadius: 1,
                                        p: 1,
                                        color: 'text.primary',
                                        whiteSpace: 'pre-wrap',
                                        wordBreak: 'break-all',
                                    }}
                                >
                                    {(() => {
                                        const parsed = safeJsonParse<unknown>(item.data, null);
                                        return parsed != null ? JSON.stringify(parsed, null, 2) : item.data;
                                    })()}
                                </Box>
                            </>
                        )}
                    </PageCard>
                );
            })}

            {/* Restore confirmation dialog */}
            <ConfirmDialog
                open={!!restoreTarget}
                onCancel={() => setRestoreTarget(null)}
                onConfirm={handleRestore}
                title="Restore Entity"
                description={
                    <>
                        <Typography variant="body2">
                            Restore <strong>{restoreTarget?.entityType}</strong> with ID <strong>{restoreTarget?.entityId}</strong>?
                        </Typography>
                        <Typography variant="body2" sx={{ mt: 1 }}>
                            The entity will be removed from the Deleted table and its JSON data returned for re-creation.
                        </Typography>
                        {restoreStatus === CallStatus.Failure && (
                            <Typography color="error" variant="body2" sx={{ mt: 1 }}>{restoreError}</Typography>
                        )}
                    </>
                }
                confirmLabel="Restore"
                tone="success"
                busy={isRestoring}
                busyLabel="Restoring..."
            />
        </PageContainer>
    );
}
