// The new backend does NOT expose any /deleted endpoints. This module is a stub kept so legacy
// admin pages don't fail to import; every call rejects with a synthetic 501 response.

import { ApiResponse, DeletedItem } from '@/types/api.types';

type DeletedResponse<T> = { data: ApiResponse<T> };

const notImplemented = <T = unknown>(): Promise<DeletedResponse<T>> =>
    Promise.reject({
        response: {
            status: 501,
            data: {
                status: 501,
                errorCode: 501,
                error: 'Deleted-items API is not available in this backend.',
            },
        },
    });

export const DeletedServicesError = {
    GetDeletedError: (_status: number) => 'Deleted-items feature is not available.',
    RestoreError:    (_status: number) => 'Restore feature is not available.',
};

export const DeletedServices = {
    GetDeleted:        (_entityType?: string) => notImplemented<DeletedItem[]>(),
    GetDeletedById:    (_entityType: string, _entityId: string) => notImplemented<DeletedItem>(),
    RestoreDeleted:    (_entityType: string, _entityId: string) => notImplemented<boolean>(),
    PermanentDelete:   (_entityType: string, _entityId: string) => notImplemented<boolean>(),
};
